import torch
import torch.nn as nn
import torchvision.models as models

class VOC2012Model(nn.Module):
    def __init__(self, num_classes=20, max_objects=5):
        super(VOC2012Model, self).__init__()
        self.max_objects = max_objects
        self.num_classes = num_classes

        resnet = models.resnet18(weights = models.ResNet18_Weights.DEFAULT)

        self.backbone = nn.Sequential(*list(resnet.children())[:-2]) 

        self.pool = nn.AdaptiveAvgPool2d((1, 1))

        self.num_features = 512

        self.box_head = nn.Sequential(
            nn.Linear(self.num_features, 256),
            nn.ReLU(),
            nn.Linear(256, max_objects * 4),
            nn.Sigmoid() 
        )

        self.class_head = nn.Sequential(
            nn.Linear(self.num_features, 256),
            nn.ReLU(),
            nn.Linear(256, max_objects * num_classes)
        )

    def forward(self, x):
        batch_size = x.size(0)
        
        features = self.backbone(x)           
        features = self.pool(features)         
        features = torch.flatten(features, 1)  
        
        pred_boxes = self.box_head(features).view(batch_size, self.max_objects, 4)
        pred_classes = self.class_head(features).view(batch_size, self.max_objects, self.num_classes)
        
        return {"pred_boxes": pred_boxes, "pred_classes": pred_classes}

if __name__ == "__main__":
    # Test thử xem mô hình ResNet tự viết có chạy mượt không
    dummy_images = torch.randn(2, 3, 224, 224)
    model = VOC2012Model(num_classes=10, max_objects=5)
    outputs = model(dummy_images)
    print("--- KIỂM TRA MẠNG RESNET THÀNH CÔNG ---")
    print("Kích thước đầu ra hộp thoại:", outputs["pred_boxes"].shape)   # [2, 5, 4]                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    print("Kích thước đầu ra nhãn lớp:", outputs["pred_classes"].shape) # [2, 5, 10]